import React, { useState, useEffect } from 'react';
import './SessionManager.css';

const SessionManager = ({ onSessionSelect, currentSession }) => {
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchSessions = async () => {
    try {
      setLoading(true);
      const response = await fetch('http://localhost:8000/api/sessions');
      const data = await response.json();

      if (response.ok) {
        setSessions(data.sessions);
        setError('');
      } else {
        setError('获取会话列表失败');
      }
    } catch (error) {
      setError('网络错误，请检查后端服务');
    } finally {
      setLoading(false);
    }
  };

  const deleteSession = async (sessionId) => {
    if (!window.confirm(`确定要删除会话 "${sessionId}" 吗？`)) return;

    try {
      const response = await fetch(`http://localhost:8000/api/sessions/${sessionId}`, {
        method: 'DELETE',
      });

      if (response.ok) {
        // 重新获取会话列表
        fetchSessions();
      } else {
        setError('删除会话失败');
      }
    } catch (error) {
      setError('网络错误');
    }
  };

  useEffect(() => {
    fetchSessions();
  }, []);

  return (
    <div className="session-manager">
      <h2>复习会话管理</h2>
      <p>管理您的复习问答会话历史记录。</p>

      <button onClick={fetchSessions} className="refresh-button">
        刷新列表
      </button>

      {loading && <p>加载中...</p>}
      {error && <p className="error">{error}</p>}

      <div className="sessions-list">
        {sessions.map((session) => (
          <div key={session.session_id} className="session-item">
            <div className="session-info">
              <span className="session-id">{session.session_id}</span>
              <span className="message-count">({session.message_count} 条消息)</span>
            </div>
            <div className="session-actions">
              <button
                onClick={() => onSessionSelect(session.session_id)}
                className={`select-button ${currentSession === session.session_id ? 'active' : ''}`}
              >
                {currentSession === session.session_id ? '当前会话' : '选择'}
              </button>
              <button
                onClick={() => deleteSession(session.session_id)}
                className="delete-button"
              >
                删除
              </button>
            </div>
          </div>
        ))}

        {sessions.length === 0 && !loading && (
          <p className="no-sessions">暂无会话记录</p>
        )}
      </div>
    </div>
  );
};

export default SessionManager;
